  `delete_flag` tinyint UNSIGNED NOT NULL DEFAULT 0 COMMENT '0未删除 1已删除',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_server_player_time`(`server_id` ASC, `player_id` ASC, `run_time` ASC) USING BTREE,
