  INDEX `idx_dungeon_run_log_player_id_id`(`player_id` ASC, `id` DESC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 10 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '副本运行日志' ROW_FORMAT = Dynamic;

